UPDATE BOOK
TITLE = #{title}, AUTHOR = #{author}, PUBLISHER = #{publisher}, PUBLISH_DATE = TO_DATE(#{publishDate}, 'YYYY-MM-DD'), CATEGORY = #{category}, RANKING = #{ranking}, REVIEW_COUNT = #{reviewCount}, RATING = #{rating}, DESCRIPTION = #{description}, PAGES = #{pages}, PRICE = #{price}, BOOK_COVER = #{bookCover}
WHERE BOOK_ID = #{bookId}
